file.content:
/* Right panel - text + image, vertically anchored to the active row via padding-top */
.timeline-panel {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-start;
  padding-top: calc(var(--active-index, 0) * (var(--row-h) + var(--row-gap)));
  min-height: 0;
  overflow: hidden;
}

.timeline-panel__content {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-start;
  gap: var(--space-lg);
  width: 100%;
  height: 100%;
  animation: panelContentIn 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

@keyframes panelContentIn {
  from {
    opacity: 0;
    transform: translateX(20px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

.timeline-panel__text {
  font-family: var(--font-mono);
  font-size: var(--slide-text-body);
  color: var(--terminal-white);
  line-height: 1.4;
  text-align: center;
  max-width: 700px;
}

.timeline-panel__text--emphasis {
  font-size: var(--slide-text-body);
  font-weight: 700;
  color: var(--dou-mint);
  max-width: 1100px;
}

.timeline-panel__list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: var(--space-md);
  max-width: 900px;
  text-align: left;
}

.timeline-panel__list li {
  font-family: var(--font-sans);
  font-size: calc(var(--slide-text-body) * 0.82);
  color: var(--dou-white-dim);
  line-height: 1.35;
  padding-left: 2rem;
  position: relative;
}

.timeline-panel__list li::before {
  content: '';
  position: absolute;
  left: 0;
  top: 0.65em;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--dou-magenta);
}

