(() => {
  const layout = document.querySelector('.timeline-layout');
  const panel = document.querySelector('.timeline-panel');
  const content = document.querySelector('.timeline-panel__content');
  const log = document.querySelector('.timeline-log');
  const items = [...document.querySelectorAll('.timeline-log__item')];
  const active = document.querySelector('.timeline-log__item--active');
  const emphasis = document.querySelector('.timeline-panel__text--emphasis');
  const list = document.querySelector('.timeline-panel__list');
  const firstBullet = document.querySelector('.timeline-panel__list li');
  const text = document.querySelector('.timeline-panel__text');
  const image = document.querySelector('.timeline-panel__image');

  return {
    location: location.hash,
    layout: layout && {
      rowH: getComputedStyle(layout).getPropertyValue('--row-h').trim(),
      rowGap: getComputedStyle(layout).getPropertyValue('--row-gap').trim(),
      activeIndex: getComputedStyle(layout).getPropertyValue('--active-index').trim(),
      rect: { w: layout.clientWidth, h: layout.clientHeight },
    },
    panel: panel && {
      paddingTop: getComputedStyle(panel).paddingTop,
      width: panel.clientWidth,
      height: panel.clientHeight,
    },
    content: content && {
      height: content.clientHeight,
      justifyContent: getComputedStyle(content).justifyContent,
    },
    activeIndexAttr: active ? items.indexOf(active) : -1,
    itemHeights: items.map(i => i.offsetHeight),
    itemOpacity: items.map(i => getComputedStyle(i).opacity),
    activeLabel: active?.textContent?.trim(),
    hero: emphasis && {
      text: emphasis.textContent?.trim(),
      height: emphasis.offsetHeight,
      width: emphasis.offsetWidth,
      maxWidth: getComputedStyle(emphasis).maxWidth,
      fontFamily: getComputedStyle(emphasis).fontFamily.split(',')[0],
      lineHeight: getComputedStyle(emphasis).lineHeight,
      isSingleLine: emphasis.offsetHeight < 80,
    },
    list: list && {
      height: list.offsetHeight,
      itemCount: list.children.length,
    },
    firstBullet: firstBullet && {
      text: firstBullet.textContent?.trim(),
      height: firstBullet.offsetHeight,
    },
    plainText: text && !emphasis ? { text: text.textContent?.trim(), height: text.offsetHeight } : null,
    image: image && {
      width: image.offsetWidth,
      height: image.offsetHeight,
      maxHeight: getComputedStyle(image).maxHeight,
    },
    rail: (() => {
      const railEl = document.querySelector('.timeline-log__list');
      const cs = railEl ? getComputedStyle(railEl, '::before') : null;
      return cs ? { width: cs.width, background: cs.background } : null;
    })(),
    logListHeight: document.querySelector('.timeline-log__list')?.offsetHeight,
  };
})()

