(async () => {
  // Advance reveal 5 times via the input field
  const input = document.querySelector('input');
  if (!input) return { error: 'no input found' };
  const setValue = (v) => {
    const setter = Object.getOwnPropertyDescriptor(input.__proto__, 'value').set;
    setter.call(input, v);
    input.dispatchEvent(new Event('input', { bubbles: true }));
  };
  for (let i = 0; i < 5; i++) {
    setValue('r');
    input.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', bubbles: true }));
    // submit via form if any
    const form = input.closest('form');
    if (form) form.dispatchEvent(new Event('submit', { bubbles: true, cancelable: true }));
    await new Promise(r => setTimeout(r, 50));
  }
  await new Promise(r => setTimeout(r, 200));
  // Query state after advancing
  const layout = document.querySelector('.timeline-layout');
  const active = document.querySelector('.timeline-log__item--active');
  const items = [...document.querySelectorAll('.timeline-log__item')];
  const emphasis = document.querySelector('.timeline-panel__text--emphasis');
  const list = document.querySelector('.timeline-panel__list');
  const bullets = [...document.querySelectorAll('.timeline-panel__list li')];
  return {
    activeIndex: getComputedStyle(layout).getPropertyValue('--active-index').trim(),
    activeLabel: active?.textContent?.trim(),
    activeIndexFromItems: items.findIndex(i => i.classList.contains('--active') || i.classList.contains('timeline-log__item--active')),
    emphasisText: emphasis?.textContent?.trim(),
    emphasisWidth: emphasis?.offsetWidth,
    emphasisHeight: emphasis?.offsetHeight,
    emphasisMaxWidth: emphasis && getComputedStyle(emphasis).maxWidth,
    emphasisColor: emphasis && getComputedStyle(emphasis).color,
    listExists: !!list,
    bulletCount: bullets.length,
    bulletTexts: bullets.map(b => b.textContent?.trim()),
    bulletFontFamily: bullets[0] && getComputedStyle(bullets[0]).fontFamily.split(',')[0],
    itemOpacities: items.map(i => getComputedStyle(i).opacity),
    activeItemMarkerBg: active && getComputedStyle(active, '::before').backgroundColor,
  };
})()

(() => {
  const items = [...document.querySelectorAll('.timeline-log__item')];
  const layoutStyle = document.querySelector('.timeline-layout')?.getAttribute('style');
  const panelContent = document.querySelector('.timeline-panel__content');
  return {
    itemDetail: items.map((i, idx) => ({
      idx,
      classes: i.className,
      text: i.textContent?.trim(),
      opacity: getComputedStyle(i).opacity,
      offsetTop: i.offsetTop,
      offsetHeight: i.offsetHeight,
    })),
    layoutStyle,
    panelContentHeight: panelContent?.offsetHeight,
    // Compute total stack height
    logListHeight: document.querySelector('.timeline-log__list')?.offsetHeight,
    // Stage 5 position check
    activePanel: (() => {
      const panel = document.querySelector('.timeline-panel');
      const em = document.querySelector('.timeline-panel__text--emphasis');
      const list = document.querySelector('.timeline-panel__list');
      return panel && {
        paddingTop: getComputedStyle(panel).paddingTop,
        emphasisOffsetTop: em && em.offsetTop,
        listOffsetTop: list && list.offsetTop,
        listOffsetHeight: list && list.offsetHeight,
      };
    })(),
  };
})()

