36	  { anchorDate: new Date(2024, 9),  text: 'copilot? крутий автокомпліт', image: null },
37	  { anchorDate: new Date(2024, 10), text: 'я не вмію у фронтенд, cursor, допоможи', image: cursorFrontend },
38	  { anchorDate: new Date(2025, 2),  text: 'а що як це не просто кодогенерація, а pair programming?', image: mentoringLlm },
39	  { anchorDate: new Date(2025, 3),  text: 'але ж це все ще іграшкова технологія, так?', image: aiTechDebt, imageClassName: 'timeline-panel__image--zoom-anim' },
40	  { anchorDate: new Date(2025, 4),  text: 'claude code? спробуймо', image: claudeCodeEmail },
41	  {
42	    anchorDate: null,
43	    text: 'не написав жодного рядка коду вручну',
44	    bullets: [
45	      'віднайшов свій комфортний ai agentic coding workflow',
46	      'євангелізую Claude Code у Superhuman: воркшопи, туторіали, 1-1',
47	      'будую внутрішні інструменти: плагіни, скіли, автономні агенти',
48	    ],
49	    image: null,
50	    emphasis: true,
51	  },
52	];
53	
54	export const TimelineSlide: SlideDefinition = {
55	  id: 'timeline',
56	  maxRevealStages: 5,
57	  content: ({ revealStage }) => {
58	    const currentStage = Math.min(revealStage, timelineItems.length - 1);
59	    const currentItem = timelineItems[currentStage];
60	
61	    return (
62	      <div className="timeline-slide-v2">
63	        <h2 className="timeline-title-v2">
64	          <span className="text-dim">$</span> моя ai coding timeline
65	        </h2>
66	
67	        <div className="timeline-layout">
68	          {/* LEFT: Git log - time markers only */}
69	          <div className="timeline-log">
70	            <div className="timeline-log__list">
71	              {timelineItems.map((item, idx) => {
72	                const isActive = idx === currentStage;
73	                const isPast = idx < currentStage;
74	                const isEmphasis = item.emphasis;
75	
76	                return (
77	                  <div
78	                    key={idx}
79	                    className={`timeline-log__item ${isActive ? 'timeline-log__item--active' : ''} ${isPast ? 'timeline-log__item--past' : ''} ${isEmphasis && isActive ? 'timeline-log__item--emphasis' : ''}`}
80	                  >
81	                    <div className={`timeline-log__time ${isEmphasis ? 'timeline-log__time--emphasis' : ''}`}>
82	                      {timeLabel(item.anchorDate)}
83	                    </div>
84	                  </div>
85	                );
86	              })}
87	            </div>
88	          </div>
89	
90	          {/* RIGHT: Content panel - text + image */}
91	          <div className="timeline-panel">
92	            <div className="timeline-panel__content" key={currentStage}>
93	              {/* Text */}
94	              {currentItem.bullets ? (
95	                <>
96	                  <div className="timeline-panel__text timeline-panel__text--emphasis">
97	                    {currentItem.text}
98	                  </div>
99	                  <ul className="timeline-panel__list">
100	                    {currentItem.bullets.map((b, i) => <li key={i}>{b}</li>)}
101	                  </ul>
102	                </>
103	              ) : (
104	                <div className={`timeline-panel__text ${currentItem.emphasis ? 'timeline-panel__text--emphasis' : ''}`}>
105	                  {currentItem.text}
106	                </div>
107	              )}
108	
109	              {/* Image if available */}
110	              {currentItem.image && (
111	                <img
112	                  src={currentItem.image}
113	                  alt={currentItem.text}
114	                  className={`timeline-panel__image ${currentItem.imageClassName ?? ''}`}
115	                  loading="lazy"
116	                />
117	              )}
118	            </div>
119	          </div>
120	        </div>
121	      </div>
122	    );
123	  },
124	};

